import{_ as d,o as e,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const I=JSON.parse('{"title":"AIUI 类型消息事件","description":"","frontmatter":{"title":"AIUI 类型消息事件"},"headers":[],"relativePath":"hardware/rk3588-mm/message-events.md","filePath":"hardware/rk3588-mm/message-events.md","lastUpdated":null}'),s={name:"hardware/rk3588-mm/message-events.md"};function o(n,t,_,i,l,h){return e(),a("div",null,[...t[0]||(t[0]=[r('<p>消息事件概述</p><p>多模态模组内置集成AIUI SDK，除了支持AIUI SDK的<a href="/sdk-dev/basics/events.html">通用消息</a>控制指令外，还增加了部分多模态交互相关的控制指令:</p><h2 id="aiui控制消息" tabindex="-1">AIUI控制消息 <a class="header-anchor" href="#aiui控制消息" aria-label="Permalink to &quot;AIUI控制消息&quot;">​</a></h2><p>通过AIUIMessage向SDK发送指令，通过AIUIEvent获取sdk事件回调。</p><p>温馨提示</p><p>有返回值的消息类型，代表向AIUI发送该消息后，AIUI会抛出EVENT_CMD_RETURN事件返回结果。</p><table tabindex="0"><thead><tr><th></th><th></th><th></th><th></th></tr></thead><tbody><tr><td>msgType（消息类型）</td><td>取值</td><td>返回值</td><td>说明</td></tr><tr><td>CMD_SET_INTERACT_MODE</td><td>1008</td><td>无</td><td><strong>设置唤醒降噪模式</strong> arg1表示类型：   0:使用人脸唤醒+唇形降噪；   1:使用语音唤醒+声学降噪</td></tr><tr><td>CMD_SET_WAKEUP_MODE</td><td>1009</td><td>无</td><td><strong>设置唤醒模式</strong> arg1表示类型：   0:使用人脸唤醒   1:使用语音唤醒</td></tr><tr><td>CMD_REGISTER_FACE</td><td>1011</td><td>有</td><td><strong>注册单个人脸信息（多人多模态版本）</strong> info字段指定data数据类型及注册人脸信息：   data_type=raw_jpeg,extend_info=base64(自定义人员信息) data字段：base64编码之后的jpeg图片数据</td></tr><tr><td>CMD_DELETE_REGISTER_FACE</td><td>1012</td><td>有</td><td><strong>删除已注册人脸</strong> <strong>info</strong>字段指定需要删除的人脸id：face_ids=xx 多个id使用&amp;分隔</td></tr><tr><td>CMD_GET_ALL_REGISTER_FACE</td><td>1013</td><td>有</td><td><strong>获取所有已注册的人脸信息</strong></td></tr></tbody></table><h2 id="本地人脸识别功能" tabindex="-1">本地人脸识别功能 <a class="header-anchor" href="#本地人脸识别功能" aria-label="Permalink to &quot;本地人脸识别功能&quot;">​</a></h2><p>机器人超脑版本V1.3及以上版本默认开启本地人脸识别功能</p><ol><li>人脸注册、删除、查询列表功能，通过AIUI消息事件管理</li><li>人脸检测结果在<a href="/hardware/rk3588-mm/video-protocol.html">视频传输协议</a>中进行接收</li></ol>',10)])])}const m=d(s,[["render",o]]);export{I as __pageData,m as default};
